    and and9  (and_stage2[1], data_in[6], sel[0],  sel1_n, sel2_n);
    and and10 (and_stage2[2], data_in[5], sel0_n, sel[1],  sel2_n);
    and and11 (and_stage2[3], data_in[4], sel[0],  sel[1],  sel2_n);
