// 3-bit Half Adder Implementation
// Note: This implementation uses half adders in a cascaded manner
// For proper 3-bit addition, full adders would be more appropriate

module half_adder(
    input a,
    input b,
    output sum,
    output carry
);
    assign sum = a ^ b;
    assign carry = a & b;
endmodule

module three_bit_adder(
    input [2:0] a,
    input [2:0] b,
    output [2:0] sum,
    output carry_out
);
    wire [2:0] ha_sum;
    wire [2:0] ha_carry;
    wire c1, c2;

    // Half adder for LSB (bit 0)
    half_adder ha0(
        .a(a[0]),
        .b(b[0]),
        .sum(sum[0]),
        .carry(ha_carry[0])
    );

    // Half adder for bit 1
    half_adder ha1(
        .a(a[1]),
        .b(b[1]),
        .sum(ha_sum[1]),
        .carry(ha_carry[1])
    );

    // Half adder for bit 2
    half_adder ha2(
        .a(a[2]),
        .b(b[2]),
        .sum(ha_sum[2]),
        .carry(ha_carry[2])
    );

    // Additional logic to handle carries
    assign c1 = ha_carry[0] | (ha_sum[1] & ha_carry[1]);
    assign sum[1] = ha_sum[1] ^ ha_carry[0];
    assign c2 = ha_carry[1] | (ha_sum[2] & ha_carry[2]);
    assign sum[2] = ha_sum[2] ^ c1;
    assign carry_out = (ha_carry[2] & ~c1) | (ha_sum[2] & c1) | (ha_carry[2] & c1);
endmodule

// Alternative implementation using full adders for proper 3-bit addition
module full_adder(
    input a,
    input b,
    input cin,
    output sum,
    output cout
);
    assign sum = a ^ b ^ cin;
    assign cout = (a & b) | (b & cin) | (a & cin);
endmodule

module three_bit_full_adder(
    input [2:0] a,
    input [2:0] b,
    output [2:0] sum,
    output carry_out
